rewritten_query:
select c_count, count(*) as custdist 
from (
    select c.c_custkey, COALESCE(o.order_count, 0) as c_count
    from customer c
    left join (
        select o_custkey, count(o_orderkey) as order_count
        from orders
        where o_comment not like '%special%requests%'
        group by o_custkey
    ) o on c.c_custkey = o.o_custkey
) as c_orders
group by c_count 
order by custdist desc, c_count desc;
